    while(T--) {
        int N; cin>>N;
        unordered_map<int,int> freq;
        int x, maxFreq=0;
        for(int i=0;i<N;++i){
            cin>>x;
            maxFreq = max(maxFreq, ++freq[x]);
        }
        cout << N - maxFreq << '\n';
    }
    return 0;
